B.a0m=s(["history","snapshot","weekly","past","historical","archive"],t.s)
B.aUf=new A.bR("History Tab","Browse weekly snapshots of your portfolio going back as far as your history allows.","Found in Analysis \u2192 History tab.\n\nEach weekly snapshot shows:\n\u2022 Portfolio total value and P&L\n\u2022 IRR at that point in time\n\u2022 Best and worst performer that week\n\u2022 Position Size card (what % each stock was)\n\u2022 Sector, Country, Currency, and Asset Class breakdown charts\n\u2022 Portfolio Quality score\n\nUse the arrows to navigate between weeks.\n\nSnapshots are recorded once per ISO week (Monday\u2013Sunday) the first time you open the app that week. They update if you open again in the same week.",null,B.a0m)
B.a4x=s(["snapshot","recorded","automatic","daily","weekly","history","data"],t.s)
B.aTV=new A.bR("How Snapshots Are Recorded","Snapshots are saved automatically \u2014 no action needed from you.","The app records several types of snapshots automatically:\n\n1. Daily portfolio snapshot (portfolio_snapshots)\n   \u2192 Recorded each time you refresh prices\n   \u2192 Used for: Equity Curve, VaR (whole portfolio)\n\n2. Daily tag snapshots (tag_daily_snapshots)\n   \u2192 Recorded per tag, same time as portfolio snapshot\n   \u2192 Used for: VaR per tag/sub-portfolio\n\n3. Weekly analysis snapshot (analysis_snapshots)\n   \u2192 Recorded once per week on app open\n   \u2192 Used for: History tab, per-tag breakdowns\n\nThe more consistently you use the app, the richer your historical data becomes.",null,B.a4x)
B.a4h=s([B.aUf,B.aTV],t.YG)
B.aTK=new A.fq("History & Snapshots",B.y0,B.dq,B.a4h)
B.a4M=s(["goal","target","retirement","savings","progress","milestone"],t.s)
B.aU4=new A.bR("Setting a Goal","Define a target portfolio value and track your progress over time.",'Go to the Goals tab \u2192 tap the + button.\n\nConfigure:\n\u2022 Goal name (e.g. "Retirement fund")\n\u2022 Target amount and currency\n\u2022 Target date\n\u2022 Asset classes to include (Stocks, Cash, Property)\n\nThe goal tracks your progress each time you refresh prices or update your cash balance.',null,B.a4M)
B.a2i=s(["goal","asset class","property","stocks","cash","net worth"],t.s)
B.aUv=new A.bR("Goal Asset Classes","Choose which types of assets count toward a goal.",'When creating a goal you select which asset classes to include:\n\n\u2022 Stocks \u2014 all your owned stock positions (in the goal\'s currency)\n\u2022 Cash \u2014 your logged cash/liquidity balance\n\u2022 Property \u2014 a manual property value you enter on the goal\n\nThis lets you create specific goals:\n\u2022 "Investment portfolio" \u2192 Stocks only\n\u2022 "Total net worth" \u2192 Stocks + Cash + Property\n\u2022 "Emergency fund" \u2192 Cash only',null,B.a2i)
B.a1J=s([B.aU4,B.aUv],t.YG)
B.aTD=new A.fq("Goals",B.mm,B.ad,B.a1J)
